package main

import (
	"context"
	"fmt"
	"log"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
)

var (
	userMetrics = prometheus.NewCounterVec(prometheus.CounterOpts{
		Name: "users",
		Help: "Number of users",
	}, []string{"username"})
	requestMetrics = prometheus.NewCounterVec(prometheus.CounterOpts{
		Name: "requests",
		Help: "Number of requests",
	}, []string{"username", "method"})
)

func main() {
	http.Handle("/metrics", prometheus.Handler())
	http.ListenAndServe(":8080", nil)
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")
	if username == "" {
		log.Println("No username provided")
		return
	}

	// Increment the user counter for the given username
	userMetrics.WithLabelValues(username).Inc()

	// Increment the request counter for the given username and method
	requestMetrics.WithLabelValues(username, r.Method).Inc()

	fmt.Fprintf(w, "Hello, %s!", username)
}